  "name": "提庇留",
  "en": "Tiberius Caesar",
  "era": "新约时代",
  "role": "君王",
  "type": "混合",
  "lesson": "王朝更替，救恩照常推进",
  "tags": [
   "君王",
   "混合型"
  ],
