  "follow_en": [
   "Hoping blood kin too come into the Lord together",
   "Treasuring the double bond of being both kin and member"
  ],
  "caution_en": [],
  "applications_en": [
   "Pray for your kin who don't yet believe",
   "Treasure and witness the relationship of 'kin who are also members'",
   "Lift blood affection into love in the Lord"
  ]
